<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('audit.view');$pageTitle='Audit History';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query('SELECT * FROM audit_logs ORDER BY id DESC LIMIT 500')->fetchAll();?><h1>Audit history</h1><p class="helper">Security-sensitive values are redacted before audit metadata is stored.</p><div class="table-wrap"><table class="table"><thead><tr><th>Time</th><th>Actor</th><th>Action</th><th>Entity</th><th>IP</th><th>Metadata</th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['created_at'])?></td><td><?=vp3_e($x['actor_type'].':'.($x['actor_id']??'system'))?></td><td><?=vp3_e($x['action'])?></td><td><?=vp3_e(($x['entity_type']??'').' '.($x['entity_uuid']??''))?></td><td><?=vp3_e($x['ip_address'])?></td><td><code><?=vp3_e($x['metadata_json'])?></code></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>
